import React, { useState, useEffect, useCallback } from "react";
import { getApiKeys } from "@/lib/serverConfig";
import { validateApiKey } from "@/lib/openrouter";

const STATUS_CONFIG = {
  none: { color: "bg-red-500", label: "No API Key" },
  invalid: { color: "bg-red-500", label: "Invalid Key" },
  exhausted: { color: "bg-red-500", label: "Credits Exhausted" },
  error: { color: "bg-orange-500", label: "Check Failed" },
  low: { color: "bg-orange-500", label: "Low Credits" },
  valid: { color: "bg-emerald-500", label: "Valid" },
  checking: { color: "bg-yellow-400 animate-pulse", label: "Checking..." },
};

export default function ApiKeyIndicator() {
  const [status, setStatus] = useState("checking");

  const check = useCallback(async () => {
    const keys = getApiKeys();
    if (!keys.length) { setStatus("none"); return; }
    setStatus("checking");
    const result = await validateApiKey(keys[0]);
    setStatus(result.status);
  }, []);

  useEffect(() => {
    check();
    const interval = setInterval(check, 60000);
    const handleStorage = () => check();
    window.addEventListener("storage", handleStorage);
    return () => { clearInterval(interval); window.removeEventListener("storage", handleStorage); };
  }, [check]);

  const config = STATUS_CONFIG[status] || STATUS_CONFIG.error;

  return (
    <div className="flex items-center gap-1.5" title={config.label}>
      <div className={`w-2 h-2 rounded-full ${config.color}`} />
      <span className="hidden lg:inline text-[10px] text-muted-foreground">{config.label}</span>
    </div>
  );
}

