import React, { useState, useEffect, useRef } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { useBotSessions } from "@/lib/BotSessionContext";
import { base44 } from "@/api/base44Client";
import { generateAiScripts } from "@/lib/aiScriptGenerator";
import { Bot, ChevronDown, Zap, Pause, Play, ExternalLink, Loader2 } from "lucide-react";

export default function AiControlMenu({ lang, theme, user, serverAddress }) {
  const { sessions, activities, startSession, pauseSession, resumeSession, activeCount, openOverlay } = useBotSessions();
  const [open, setOpen] = useState(false);
  const [generating, setGenerating] = useState(false);
  const [actors, setActors] = useState([]);
  const navigate = useNavigate();
  const location = useLocation();
  const ref = useRef(null);

  useEffect(() => {
    base44.entities.AiActor.list("-created_date", 20).then(setActors).catch(() => {});
  }, []);

  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleGenerate = async () => {
    setOpen(false);
    setGenerating(true);
    try {
      const scripts = await generateAiScripts({ actors, language: lang, user, localMode: !serverAddress });
      scripts.forEach(script => {
        startSession({
          actor: script.actor,
          type: script.action_type === "comment_on_post" ? "comment" : "post",
          targetPostId: script.target_post_id,
          language: script.language || lang,
          localMode: !serverAddress,
          parentUserName: user?.full_name || user?.email || "Unknown",
          titleScript: script.title || "",
          bodyScript: script.body || "",
          keyDelay: 500,
        });
      });
    } finally {
      setGenerating(false);
    }
  };

  const handleActivityClick = (activity) => {
    setOpen(false);
    const session = sessions.find((s) => s.id === activity.sessionId);
    if (activity.type === "post" && activity.createdRecordId) {
      navigate(`/${lang}/post/${activity.createdRecordId}`);
    } else if (activity.type === "post" && session) {
      openOverlay(session.id);
    } else if (activity.targetPostId) {
      navigate(`/${lang}/post/${activity.targetPostId}`);
    } else if (session && session.pendingNav) {
      navigate(session.pendingNav);
    }
  };

  return (
    <div className="relative" ref={ref}>
      <button
        onClick={() => setOpen(!open)}
        disabled={generating}
        className={`relative flex items-center gap-1.5 px-2.5 py-1.5 rounded-md text-xs font-medium transition-colors ${theme.badge} ${theme.cardHover} disabled:opacity-50`}
      >
        {generating ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Bot className="w-3.5 h-3.5" />}
        <span className="hidden sm:inline">AI</span>
        {activeCount > 0 && (
          <span className="absolute -top-1 -right-1 w-4 h-4 bg-emerald-500 text-white text-[9px] font-bold rounded-full flex items-center justify-center">
            {activeCount}
          </span>
        )}
        <ChevronDown className="w-3 h-3" />
      </button>

      {open && (
        <div className={`absolute right-0 mt-2 w-72 ${theme.card} border ${theme.border} rounded-xl shadow-xl z-50 overflow-hidden`}>
          <div className="p-3">
            <button
              onClick={handleGenerate}
              disabled={generating || actors.length === 0}
              className={`w-full flex items-center justify-center gap-2 ${theme.accent} ${theme.accentHover} px-3 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50`}
            >
              {generating ? <Loader2 className="w-4 h-4 animate-spin" /> : <Zap className="w-4 h-4" />}
              {generating ? "Generating..." : "Generate AI Work"}
            </button>
          </div>

          {activities.length > 0 && (
            <div className={`border-t ${theme.border} max-h-64 overflow-y-auto`}>
              {activities.slice().reverse().map((a) => {
                const session = sessions.find((s) => s.id === a.sessionId);
                const isActive = session && ["typing", "thinking", "completing", "backspace", "delete", "delay", "navigating"].includes(session.status);
                const isPaused = session && session.status === "paused";
                return (
                  <div
                    key={a.id}
