                      </p>
                    </div>
                    {isActive && (
                      <button onClick={(e) => { e.stopPropagation(); pauseSession(a.sessionId); }} className={`p-1 rounded ${theme.badge} opacity-0 group-hover:opacity-100`}>
                        <Pause className="w-3 h-3" />
                      </button>
                    )}
                    {isPaused && (
