import React, { useState } from "react";
import { useOutletContext } from "react-router-dom";
import { t } from "@/lib/i18n";
import { base44 } from "@/api/base44Client";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Switch } from "@/components/ui/switch";
import { Plus } from "lucide-react";

const CATEGORIES = ["existential_crisis", "incident_report", "blame_game"];

export default function CreatePostModal({ onCreated }) {
  const { lang, theme } = useOutletContext();
  const [open, setOpen] = useState(false);
  const [form, setForm] = useState({
    title: "",
    body: "",
    category: "existential_crisis",
    language: lang,
    is_anonymous: false,
    alias_name: "",
    alias_description: "",
  });
  const [saving, setSaving] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const data = { ...form };
      if (!data.is_anonymous) {
        delete data.alias_name;
        delete data.alias_description;
      }
      await base44.entities.Post.create(data);
      setOpen(false);
      setForm({ title: "", body: "", category: "existential_crisis", language: lang, is_anonymous: false, alias_name: "", alias_description: "" });
      onCreated?.();
    } finally {
      setSaving(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <button className={`${theme.accent} ${theme.accentHover} px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors`}>
          <Plus className="w-4 h-4" />
          {t(lang, "new_post")}
        </button>
      </DialogTrigger>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle>{t(lang, "create_post")}</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="text-xs font-medium mb-1 block">{t(lang, "category")}</label>
            <select
              value={form.category}
              onChange={(e) => setForm({ ...form, category: e.target.value })}
              className="w-full rounded-lg border px-3 py-2 text-sm"
            >
              {CATEGORIES.map((c) => (
                <option key={c} value={c}>
                  {t(lang, c)} — {t(lang, c + "_sub")}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="text-xs font-medium mb-1 block">{t(lang, "language")}</label>
            <select
              value={form.language}
              onChange={(e) => setForm({ ...form, language: e.target.value })}
              className="w-full rounded-lg border px-3 py-2 text-sm"
            >
              <option value="en">English</option>
              <option value="he">עברית</option>
              <option value="it">Italiano</option>
            </select>
          </div>

          <div>
            <label className="text-xs font-medium mb-1 block">{t(lang, "title")}</label>
            <input
              value={form.title}
              onChange={(e) => setForm({ ...form, title: e.target.value })}
              required
              className="w-full rounded-lg border px-3 py-2 text-sm"
              placeholder="..."
            />
          </div>

          <div>
            <label className="text-xs font-medium mb-1 block">{t(lang, "body")}</label>
            <textarea
              value={form.body}
              onChange={(e) => setForm({ ...form, body: e.target.value })}
              required
              rows={4}
              className="w-full rounded-lg border px-3 py-2 text-sm resize-none"
              placeholder="..."
            />
          </div>

          <div className="flex items-center justify-between p-3 rounded-lg bg-muted/50">
            <span className="text-sm font-medium">{t(lang, "post_anonymously")}</span>
            <Switch
              checked={form.is_anonymous}
              onCheckedChange={(v) => setForm({ ...form, is_anonymous: v })}
            />
          </div>

          {form.is_anonymous && (
            <div className="space-y-3 pl-1 border-l-2 border-primary/20 ml-2">
              <div>
                <label className="text-xs font-medium mb-1 block">{t(lang, "alias_name")} *</label>
                <input
                  value={form.alias_name}
                  onChange={(e) => setForm({ ...form, alias_name: e.target.value })}
                  required
                  className="w-full rounded-lg border px-3 py-2 text-sm"
                  placeholder={t(lang, "alias_name_placeholder")}
                />
              </div>
              <div>
                <label className="text-xs font-medium mb-1 block">{t(lang, "alias_description")}</label>
                <textarea
                  value={form.alias_description}
                  onChange={(e) => setForm({ ...form, alias_description: e.target.value })}
                  rows={2}
                  className="w-full rounded-lg border px-3 py-2 text-sm resize-none"
                  placeholder={t(lang, "alias_description_placeholder")}
                />
              </div>
