          <div className="flex justify-end gap-2 pt-2">
            <button type="button" onClick={() => setOpen(false)} className="px-4 py-2 text-sm rounded-lg hover:bg-muted transition-colors">
              {t(lang, "cancel")}
            </button>
            <button type="submit" disabled={saving} className={`${theme.accent} ${theme.accentHover} px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50`}>
              {saving ? "..." : t(lang, "submit")}
