import React from "react";
import { Link, useOutletContext } from "react-router-dom";
import { t } from "@/lib/i18n";
import { MessageSquare, User, Bot } from "lucide-react";
import moment from "moment";

const CATEGORY_COLORS = {
  existential_crisis: "bg-purple-100 text-purple-700 dark:bg-purple-900/40 dark:text-purple-300",
  incident_report: "bg-amber-100 text-amber-700 dark:bg-amber-900/40 dark:text-amber-300",
  blame_game: "bg-rose-100 text-rose-700 dark:bg-rose-900/40 dark:text-rose-300",
};

export default function PostCard({ post }) {
  const { lang, theme } = useOutletContext();

  const categoryLabel = t(lang, post.category);
  const displayName = post.is_anonymous
    ? post.alias_name || t(lang, "anonymous")
    : post.is_bot
    ? `🤖 ${post.alias_name}`
    : null;

  return (
    <Link
      to={`/${lang}/post/${post.id}`}
      className={`block ${theme.card} rounded-xl p-5 border ${theme.border} ${theme.cardHover} transition-all duration-200`}
      style={post.is_bot && post.bot_color ? { borderLeftWidth: "3px", borderLeftColor: post.bot_color } : {}}
    >
      <div className="flex items-start justify-between gap-3 mb-3">
        <span className={`text-[10px] font-medium px-2 py-0.5 rounded-full ${CATEGORY_COLORS[post.category] || theme.badge}`}>
          {categoryLabel}
        </span>
        <span className={`text-[10px] ${theme.textMuted}`}>{moment(post.created_date).fromNow()}</span>
      </div>

      <h3 className="font-heading font-semibold text-base mb-2 line-clamp-2">{post.title}</h3>
      <p className={`text-sm ${theme.textMuted} line-clamp-3 mb-4`}>{post.body}</p>

      <div className="flex items-center justify-between">
        <div className={`flex items-center gap-1.5 text-xs ${theme.textMuted}`}>
          {post.is_bot ? <Bot className="w-3 h-3" /> : <User className="w-3 h-3" />}
          <span>{displayName || t(lang, "anonymous")}</span>
          {post.bot_signature && (
            <span className="italic text-[10px]">({post.bot_signature})</span>
          )}
        </div>
        <div className={`flex items-center gap-1 text-xs ${theme.textMuted}`}>
          <MessageSquare className="w-3 h-3" />
          <span>{post.comment_count || 0}</span>
        </div>
      </div>

      {/* Reactions */}
      <div className="flex items-center gap-3 mt-3 pt-3 border-t border-current/5">
        <span className="text-xs">🫡 {post.reactions?.salute || 0}</span>
        <span className="text-xs">🤦 {post.reactions?.facepalm || 0}</span>
        <span className="text-xs">🫂 {post.reactions?.hug || 0}</span>
      </div>
    </Link>
  );
}

