import React, { useState, useEffect } from "react";
import { Outlet, Link, useParams, useNavigate, useLocation } from "react-router-dom";
import { t, SUPPORTED_LANGS, LANG_LABELS, isRTL } from "@/lib/i18n";
import { THEMES } from "@/lib/themes";
import { getTheme, setThemePref, getServerAddress } from "@/lib/serverConfig";
import { base44 } from "@/api/base44Client";
import { Shield, Home, LayoutDashboard, Bot, FileText, Settings, LogOut, Menu, X, Globe, Sun, Moon, Cloud } from "lucide-react";
import ApiKeyIndicator from "@/components/header/ApiKeyIndicator";
import AiControlMenu from "@/components/header/AiControlMenu";
import ActivityLog from "@/components/bot/ActivityLog";
import BotTypingOverlay from "@/components/bot/BotTypingOverlay";
import { useBotSessions } from "@/lib/BotSessionContext";

export default function AppLayout() {
  const { lang } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  const currentLang = SUPPORTED_LANGS.includes(lang) ? lang : "en";
  const rtl = isRTL(currentLang);

  const [themeName, setThemeName] = useState(getTheme());
  const [mobileOpen, setMobileOpen] = useState(false);
  const [filterLang, setFilterLang] = useState("all");
  const [user, setUser] = useState(null);

  const { pendingNav, clearPendingNav } = useBotSessions();

  const theme = THEMES[themeName] || THEMES.light;

  useEffect(() => {
    base44.auth.me().then(setUser).catch(() => {});
  }, []);

  // Handle pending bot navigation
  useEffect(() => {
    if (pendingNav) {
      navigate(pendingNav);
      clearPendingNav();
    }
  }, [pendingNav, navigate, clearPendingNav]);

  const switchLang = (newLang) => {
    const rest = location.pathname.replace(`/${currentLang}`, "");
    navigate(`/${newLang}${rest || "/feed"}${location.search}`);
  };

  const switchTheme = (t) => {
    setThemeName(t);
    setThemePref(t);
  };

  const serverAddress = getServerAddress();
  const navItems = [
    { key: "feed", icon: Home, path: `/${currentLang}/feed` },
    { key: "dashboard", icon: LayoutDashboard, path: `/${currentLang}/dashboard` },
    { key: "simulation", icon: Bot, path: `/${currentLang}/simulation` },
    { key: "openapi_doc", icon: FileText, path: `/${currentLang}/openapi` },
    { key: "settings", icon: Settings, path: `/${currentLang}/settings` },
  ];

  const themeIcons = { light: Sun, dark: Moon, blue: Cloud };

  return (
    <div className={`min-h-screen ${theme.bg} ${theme.text} transition-colors duration-300`} dir={rtl ? "rtl" : "ltr"}>
      {/* Header */}
      <header className={`sticky top-0 z-50 ${theme.headerBg}`}>
        <div className="max-w-6xl mx-auto px-4 h-14 flex items-center justify-between gap-3">
          <Link to={`/${currentLang}/feed`} className="flex items-center gap-2 shrink-0">
            <Shield className="w-5 h-5" />
            <span className="font-heading font-bold text-sm tracking-wide">{t(currentLang, "app_name")}</span>
          </Link>

          {/* Desktop Nav */}
          <nav className="hidden md:flex items-center gap-1">
            {navItems.map((item) => {
              const Icon = item.icon;
              const active = location.pathname.startsWith(item.path);
              return (
                <Link
                  key={item.key}
                  to={item.path}
                  className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                    active ? theme.accent + " " + theme.accentHover : theme.textMuted + " hover:opacity-80"
                  }`}
                >
                  <Icon className="w-3.5 h-3.5" />
                  {t(currentLang, item.key)}
                </Link>
              );
            })}
          </nav>

          {/* Controls */}
          <div className="flex items-center gap-2">
            {/* Language filter */}
            <div className="hidden md:flex items-center gap-1">
              <Globe className={`w-3.5 h-3.5 ${theme.textMuted}`} />
              <select
                value={filterLang}
                onChange={(e) => setFilterLang(e.target.value)}
                className={`text-xs rounded px-1.5 py-1 ${theme.input} border-0 outline-none`}
              >
                <option value="all">{t(currentLang, "all_languages")}</option>
                {SUPPORTED_LANGS.map((l) => (
                  <option key={l} value={l}>{LANG_LABELS[l]}</option>
                ))}
              </select>
            </div>

            {/* UI Language */}
            <select
              value={currentLang}
              onChange={(e) => switchLang(e.target.value)}
              className={`text-xs rounded px-1.5 py-1 ${theme.input} border-0 outline-none`}
            >
              {SUPPORTED_LANGS.map((l) => (
                <option key={l} value={l}>{LANG_LABELS[l]}</option>
              ))}
            </select>

            {/* Theme */}
            <div className="hidden md:flex items-center gap-0.5">
              {Object.keys(THEMES).map((tk) => {
                const TIcon = themeIcons[tk];
                return (
                  <button
                    key={tk}
                    onClick={() => switchTheme(tk)}
                    className={`p-1.5 rounded transition-colors ${themeName === tk ? theme.accent : theme.textMuted + " hover:opacity-80"}`}
                  >
                    <TIcon className="w-3.5 h-3.5" />
                  </button>
                );
              })}
            </div>

            <ApiKeyIndicator />
            <AiControlMenu lang={currentLang} theme={theme} user={user} serverAddress={serverAddress} />
            {/* Status dot */}
            <div className={`w-2 h-2 rounded-full ${serverAddress ? "bg-emerald-500" : "bg-red-500"}`} title={serverAddress ? t(currentLang, "connected") : t(currentLang, "disconnected")} />

            {/* Mobile toggle */}
            <button onClick={() => setMobileOpen(!mobileOpen)} className="md:hidden p-1">
              {mobileOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
            </button>
          </div>
        </div>

        {/* Mobile Menu */}
        {mobileOpen && (
          <div className={`md:hidden ${theme.card} border-t ${theme.border} px-4 py-3 space-y-2`}>
            {navItems.map((item) => {
              const Icon = item.icon;
              return (
                <Link
                  key={item.key}
                  to={item.path}
                  onClick={() => setMobileOpen(false)}
                  className={`flex items-center gap-2 px-3 py-2 rounded-md text-sm ${theme.textMuted} hover:opacity-80`}
                >
                  <Icon className="w-4 h-4" />
                  {t(currentLang, item.key)}
                </Link>
              );
            })}
            <div className="flex items-center gap-1 pt-2 border-t border-current/10">
              {Object.keys(THEMES).map((tk) => {
                const TIcon = themeIcons[tk];
                return (
                  <button key={tk} onClick={() => switchTheme(tk)} className={`p-2 rounded ${themeName === tk ? theme.accent : theme.textMuted}`}>
                    <TIcon className="w-4 h-4" />
                  </button>
                );
              })}
            </div>
            <div className="flex items-center gap-2 pt-2">
              <Globe className={`w-4 h-4 ${theme.textMuted}`} />
              <select value={filterLang} onChange={(e) => setFilterLang(e.target.value)} className={`text-sm rounded px-2 py-1 ${theme.input} flex-1`}>
                <option value="all">{t(currentLang, "all_languages")}</option>
                {SUPPORTED_LANGS.map((l) => (<option key={l} value={l}>{LANG_LABELS[l]}</option>))}
              </select>
            </div>
          </div>
        )}
      </header>

      {/* Content */}
      <main className="max-w-6xl mx-auto px-4 py-6">
        <Outlet context={{ lang: currentLang, theme, themeName, filterLang, user }} />
      </main>

      {/* Footer */}
      <footer className={`${theme.border} border-t mt-auto`}>
        <div className={`max-w-6xl mx-auto px-4 py-4 text-center text-xs ${theme.textMuted}`}>
          {t(currentLang, "app_name")} · {t(currentLang, "tagline")}
        </div>
      </footer>

      <ActivityLog lang={currentLang} theme={theme} />
      <BotTypingOverlay theme={theme} />
    </div>
  );
}

