import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useBotSessions } from "@/lib/BotSessionContext";
import { Pin, Minimize2, Activity, Pause, Play, CheckCircle, AlertCircle } from "lucide-react";

export default function ActivityLog({ lang, theme }) {
  const { activities, sessions, pauseSession, resumeSession, openOverlay } = useBotSessions();
  const navigate = useNavigate();
  const [minimized, setMinimized] = useState(false);
  const [pinned, setPinned] = useState(true);

  if (activities.length === 0) return null;

  const handleActivityClick = (activity) => {
    const session = sessions.find((s) => s.id === activity.sessionId);
    if (activity.type === "post" && activity.createdRecordId) {
      navigate(`/${lang}/post/${activity.createdRecordId}`);
    } else if (activity.type === "post" && session) {
      openOverlay(session.id);
    } else if (activity.targetPostId) {
      navigate(`/${lang}/post/${activity.targetPostId}`);
    } else if (session && session.pendingNav) {
      navigate(session.pendingNav);
    }
  };

  const statusIcon = (status) => {
    if (status === "completed") return <CheckCircle className="w-3 h-3 text-emerald-500" />;
    if (status === "error") return <AlertCircle className="w-3 h-3 text-red-500" />;
    return <Activity className="w-3 h-3 text-blue-500 animate-pulse" />;
  };

  if (minimized) {
    return (
      <button
        onClick={() => setMinimized(false)}
        className={`fixed bottom-4 right-4 z-50 ${theme.accent} px-3 py-2 rounded-full text-xs font-medium flex items-center gap-2 shadow-lg`}
      >
        <Activity className="w-3.5 h-3.5" />
        {activities.filter((a) => a.status === "active" || a.status === "paused").length} active
      </button>
    );
  }

  return (
    <div className={`fixed bottom-4 right-4 z-50 w-80 ${theme.card} border ${theme.border} rounded-xl shadow-2xl overflow-hidden`}>
      <div className={`flex items-center justify-between px-3 py-2 ${theme.secondaryBg} border-b ${theme.border}`}>
        <span className="text-xs font-semibold flex items-center gap-1.5">
          <Activity className="w-3.5 h-3.5" />
          Activity Log
        </span>
        <div className="flex items-center gap-1">
          <button onClick={() => setPinned(!pinned)} className={`p-1 rounded ${pinned ? theme.accent : theme.badge}`} title="Pin">
            <Pin className="w-3 h-3" />
          </button>
          <button onClick={() => setMinimized(true)} className={`p-1 rounded ${theme.badge}`} title="Minimize">
            <Minimize2 className="w-3 h-3" />
          </button>
        </div>
      </div>
      <div className="max-h-80 overflow-y-auto">
        {activities.slice().reverse().map((a) => {
          const session = sessions.find((s) => s.id === a.sessionId);
          const isActive = session && ["typing", "thinking", "completing"].includes(session.status);
          const isPaused = session && session.status === "paused";
          return (
            <div
              key={a.id}
              className={`flex items-center gap-2 px-3 py-2 border-b ${theme.border} ${theme.cardHover} cursor-pointer group`}
              onClick={() => handleActivityClick(a)}
            >
              <div className="w-2 h-2 rounded-full shrink-0" style={{ backgroundColor: a.actor?.color || "#888" }} />
              <div className="flex-1 min-w-0">
                <p className="text-xs font-medium truncate">{a.action}</p>
                <p className={`text-[10px] ${theme.textMuted} truncate`}>
                  {a.status === "completed" ? a.result || "Completed" : a.status === "error" ? "Failed" : isPaused ? "Paused" : isActive ? "Working..." : a.status}
                </p>
              </div>
              {statusIcon(a.status)}
              {isActive && (
                <button onClick={(e) => { e.stopPropagation(); pauseSession(a.sessionId); }} className="opacity-0 group-hover:opacity-100 p-1 rounded hover:bg-muted">
                  <Pause className="w-3 h-3" />
                </button>
              )}
              {isPaused && (
                <button onClick={(e) => { e.stopPropagation(); resumeSession(a.sessionId); }} className="opacity-0 group-hover:opacity-100 p-1 rounded hover:bg-muted">
                  <Play className="w-3 h-3" />
                </button>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

