import React from "react";
import { useBotSessions } from "@/lib/BotSessionContext";
import BotTypingView from "@/components/bot/BotTypingView";
import { X } from "lucide-react";

export default function BotTypingOverlay({ theme }) {
  const { overlaySessionId, closeOverlay, getSession, pauseSession, resumeSession, updateSessionText, updateSessionTitle } = useBotSessions();

  if (!overlaySessionId) return null;
  const session = getSession(overlaySessionId);
  if (!session) return null;

  const handleTextChange = (text, isTitle) => {
    if (isTitle) updateSessionTitle(session.id, text);
    else updateSessionText(session.id, text);
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
      <div className="w-full max-w-2xl max-h-[90vh] overflow-y-auto">
        <div className="flex items-center justify-between mb-3">
          <h2 className="text-sm font-semibold text-white flex items-center gap-2">
            🤖 AI Session — {session.type === "post" ? "Creating Post" : "Writing Comment"}
          </h2>
          <button onClick={closeOverlay} className="text-white/70 hover:text-white">
            <X className="w-5 h-5" />
          </button>
        </div>
        <BotTypingView
          session={session}
          theme={theme}
          onPause={() => pauseSession(session.id)}
          onResume={(editedText) => resumeSession(session.id, editedText)}
          onTextChange={handleTextChange}
          editable
        />
        {session.localMode && (
          <p className="text-center text-xs text-white/50 mt-2">⚠️ Non-server mode — no records will be saved</p>
        )}
      </div>
    </div>
  );
}

