import React, { useState } from "react";
import { useBotSessions } from "@/lib/BotSessionContext";
import { Bot, Pause, Play, Loader2 } from "lucide-react";

const ACTION_BADGES = {
  thinking: { icon: "💭", label: "Thinking...", color: "bg-yellow-100 text-yellow-700" },
  typing: { icon: "⌨️", label: "Typing...", color: "bg-emerald-100 text-emerald-700" },
  backspace: { icon: "⌫", label: "Backspace", color: "bg-orange-100 text-orange-700" },
  delete: { icon: "⌦", label: "Delete", color: "bg-red-100 text-red-700" },
  delay: { icon: "⏱", label: "Pausing", color: "bg-blue-100 text-blue-700" },
  navigating: { icon: "🔀", label: "Navigating...", color: "bg-purple-100 text-purple-700" },
  paused: { icon: "⏸", label: "Paused", color: "bg-orange-100 text-orange-700" },
  completing: { icon: "💾", label: "Saving...", color: "bg-blue-100 text-blue-700" },
  completed: { icon: "✅", label: "Completed", color: "bg-emerald-100 text-emerald-700" },
  error: { icon: "❌", label: "Error", color: "bg-red-100 text-red-700" },
};

export default function BotTypingView({ session, theme, onPause, onResume, onTextChange, editable = false }) {
  const isPaused = session.status === "paused";
  const [editText, setEditText] = useState(session.currentText);
  const badge = ACTION_BADGES[session.status] || ACTION_BADGES.typing;
  const showCursor = ["typing", "backspace", "delete"].includes(session.status);

  const handlePause = () => {
    setEditText(session.currentText);
    onPause?.();
  };

  const handleResume = () => {
    if (editText !== session.currentText) onResume?.(editText);
    else onResume?.();
  };

  return (
    <div className={`${theme.card} rounded-xl border-2 p-5 space-y-3`} style={{ borderColor: session.actor.color }}>
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full flex items-center justify-center text-white text-xs font-bold" style={{ backgroundColor: session.actor.color }}>
            <Bot className="w-4 h-4" />
          </div>
          <div>
            <p className="text-sm font-semibold">{session.actor.name}</p>
            <p className={`text-[10px] ${theme.textMuted} italic`}>{session.actor.personality} · child of {session.parentUserName}</p>
          </div>
        </div>
        <div className="flex items-center gap-1.5">
          <span className={`text-[10px] px-2 py-0.5 rounded-full font-medium ${badge.color}`}>
            {badge.icon} {badge.label}
          </span>
          {isPaused ? (
            <button onClick={handleResume} className={`flex items-center gap-1 text-xs px-2 py-1 rounded ${theme.accent}`}>
              <Play className="w-3 h-3" /> Resume
            </button>
          ) : session.status === "completed" || session.status === "error" ? null : (
            <button onClick={handlePause} className={`flex items-center gap-1 text-xs px-2 py-1 rounded ${theme.badge}`}>
              <Pause className="w-3 h-3" /> Pause
            </button>
          )}
        </div>
      </div>

      {/* Title (for posts) */}
      {session.type === "post" && (
        <div>
          {isPaused && editable ? (
            <input
              value={session.currentTitle}
              onChange={(e) => onTextChange?.(e.target.value, true)}
              className={`w-full rounded-lg px-3 py-2 text-sm font-heading font-semibold border-2 ${theme.input}`}
              placeholder="Title..."
            />
          ) : (
            <h3 className="font-heading font-semibold text-base px-3 py-1 min-h-[2rem]">
              {session.currentTitle}
              {showCursor && session.phase === "title" && <span className="inline-block w-0.5 h-4 ml-0.5 bg-current animate-pulse" />}
            </h3>
          )}
        </div>
      )}

      {/* Body */}
      {isPaused && editable ? (
        <textarea
          value={editText}
          onChange={(e) => setEditText(e.target.value)}
          rows={5}
          className={`w-full rounded-lg px-3 py-2 text-sm resize-none border-2 ${theme.input}`}
          placeholder="Edit the bot's text..."
        />
      ) : (
        <div className={`text-sm leading-relaxed whitespace-pre-wrap px-3 py-2 min-h-[80px] ${theme.secondaryBg} rounded-lg`}>
          {session.currentText}
          {showCursor && session.phase === "body" && <span className="inline-block w-0.5 h-4 ml-0.5 bg-current animate-pulse" />}
        </div>
      )}

      {isPaused && (
        <p className={`text-[10px] ${theme.textMuted} italic`}>
          ✏️ Edit the text above, then click Resume. The bot will process your changes and continue from its original intention.
        </p>
      )}
    </div>
  );
}

