import { generateFallbackScript } from "@/lib/botTextGenerator";

export async function generateAiScripts({ actors, language, user, localMode }) {
  let posts = [];
  try {
    posts = await base44.entities.Post.list("-created_date", 10);
  } catch {}

  const userName = user?.full_name || user?.email || "Unknown";

  const prompt = `You are designing bot activity for "Never Again", a social platform for security guards to share shift failures and process professional shame.

EXISTING POSTS on the platform:
${posts.length > 0 ? posts.map(p => `- ID: ${p.id} | Title: "${p.title}" | Category: ${p.category} | Language: ${p.language} | Preview: "${(p.body || '').substring(0, 80)}..."`).join('\n') : 'No posts exist yet. Bots should create new posts.'}

BOT IDENTITIES:
${actors.map(a => `- Name: ${a.name} | Personality: ${a.personality} | Description: ${a.description}`).join('\n')}

Design ${Math.min(actors.length, 3)} bot actions. Each action is either:
1. "create_post" — the bot creates a new post
2. "comment_on_post" — the bot comments on an existing post (set target_post_id to a real post ID from above)

For each action, write the title and body text WITH SPECIAL CONTROL CHARACTERS embedded to simulate realistic typing:
- ⏱N = pause for N milliseconds (e.g., ⏱500 = 0.5 second pause before next char)
- ⌫N = press backspace N times, removing N characters from what was typed (e.g., ⌫3 = remove last 3 chars)
- ⌦N = press delete N times (e.g., ⌦2 = delete 2 chars)
- 💭N = enter "thinking" state for N milliseconds (e.g., 💭2000 = think for 2 seconds, showing regret or reconsideration)
- 🔀PATH = navigate to a page (e.g., 🔀/${language}/post/POST_ID_HERE — use real post IDs from above)
- ⏎ = press enter (newline)

EXAMPLE body: "So I⏱300 fell asleep⌫11 was resting my eyes💭1000 at the post🔀/${language}/feed⏎ and nobody noticed."

Make the text reflect each bot's personality. Include at least 3 control characters per action. Use real post IDs from above for navigation and comments. For new posts, you can navigate to 🔀/${language}/feed.

Return a JSON object with a "scripts" array.`;

  try {
    const response = await base44.integrations.Core.InvokeLLM({
      prompt,
      response_json_schema: {
        type: "object",
        properties: {
          scripts: {
            type: "array",
            items: {
              type: "object",
              properties: {
                actor_name: { type: "string" },
                action_type: { type: "string" },
                target_post_id: { type: "string" },
                title: { type: "string" },
                body: { type: "string" },
                category: { type: "string" },
                language: { type: "string" },
              },
            },
          },
        },
      },
    });

    return (response.scripts || []).map(script => {
      const actor = actors.find(a => a.name === script.actor_name) || actors[0];
      if (!actor) return null;
      return { ...script, actor };
    }).filter(Boolean);
  } catch {
    // Fallback: generate scripts from templates with control chars
    return actors.slice(0, Math.min(3, actors.length)).map(actor => {
      const fallback = generateFallbackScript(actor);
      const isComment = posts.length > 0 && Math.random() > 0.5;
      return {
        actor,
        action_type: isComment ? "comment_on_post" : "create_post",
        target_post_id: isComment ? posts[Math.floor(Math.random() * posts.length)].id : null,
        title: fallback.title,
        body: fallback.body,
        category: ["existential_crisis", "incident_report", "blame_game"][Math.floor(Math.random() * 3)],
        language,
      };
    });
  }
}

