// Special control characters for bot typing simulation
export const CONTROL_CHARS = {
  DELAY: '⏱',      // ⏱500 = delay 500ms
  BACKSPACE: '⌫',   // ⌫3 = backspace 3 chars
  DELETE: '⌦',      // ⌦2 = delete 2 chars
  THINK: '💭',       // 💭1000 = think for 1000ms
  NAVIGATE: '🔀',    // 🔀/en/post/123 = navigate to path
  ENTER: '⏎',       // ⏎ = press enter (newline)
};

// Parse one action from the script at the given position
// Returns: { action: 'char'|'delay'|'backspace'|'delete'|'think'|'navigate'|'enter'|'done', ...newPos }
export function parseNextAction(script, pos) {
  if (pos >= script.length) return { action: 'done', newPos: pos };
  const char = script[pos];

  if (char === CONTROL_CHARS.DELAY) {
    const { number, newPos } = readNumber(script, pos + 1);
    return { action: 'delay', ms: number || 500, newPos };
  }
  if (char === CONTROL_CHARS.BACKSPACE) {
    const { number, newPos } = readNumber(script, pos + 1);
    return { action: 'backspace', count: number || 1, newPos };
  }
  if (char === CONTROL_CHARS.DELETE) {
    const { number, newPos } = readNumber(script, pos + 1);
    return { action: 'delete', count: number || 1, newPos };
  }
  if (char === CONTROL_CHARS.THINK) {
    const { number, newPos } = readNumber(script, pos + 1);
    return { action: 'think', ms: number || 1000, newPos };
  }
  if (char === CONTROL_CHARS.NAVIGATE) {
    const { path, newPos } = readPath(script, pos + 1);
    return { action: 'navigate', path, newPos };
  }
  if (char === CONTROL_CHARS.ENTER) {
    return { action: 'enter', newPos: pos + 1 };
  }
  return { action: 'char', char, newPos: pos + 1 };
}

function readNumber(str, start) {
  let i = start;
  let numStr = '';
  while (i < str.length && /\d/.test(str[i])) { numStr += str[i]; i++; }
  return { number: parseInt(numStr, 10) || 0, newPos: i };
}

function readPath(str, start) {
  let i = start;
  let path = '';
  while (i < str.length && !isControlChar(str[i]) && !/\s/.test(str[i])) { path += str[i]; i++; }
  return { path, newPos: i };
}

function isControlChar(char) {
  return Object.values(CONTROL_CHARS).includes(char);
}

// Strip control characters for display (when saving the final text)
export function stripControlChars(text) {
  let result = '';
  let i = 0;
  while (i < text.length) {
    const char = text[i];
    if (isControlChar(char)) {
      // Skip the control char and its parameter
      if (char === CONTROL_CHARS.ENTER) { i++; continue; }
      i++;
      while (i < text.length && /\d/.test(text[i])) i++;
      // For navigate, skip the path
      if (char === CONTROL_CHARS.NAVIGATE) {
        while (i < text.length && !isControlChar(text[i]) && !/\s/.test(text[i])) i++;
      }
    } else {
      result += char;
      i++;
    }
  }
  return result;
}

