// Manages server address from URL params and localStorage
export function getServerAddress() {
  const urlParams = new URLSearchParams(window.location.search);
  const fromUrl = urlParams.get("server");
  if (fromUrl) {
    localStorage.setItem("na_server_address", fromUrl);
    return fromUrl;
  }
  return localStorage.getItem("na_server_address") || "";
}

