  localStorage.setItem("na_server_address", address);
  const url = new URL(window.location.href);
  if (address) {
    url.searchParams.set("server", address);
  } else {
    url.searchParams.delete("server");
  }
  window.history.replaceState({}, "", url.toString());
}

