import React, { createContext, useContext, useState, useRef, useCallback, useEffect } from "react";
import { base44 } from "@/api/base44Client";
import { parseNextAction, stripControlChars } from "@/lib/scriptParser";

const BotSessionContext = createContext(null);
export const useBotSessions = () => useContext(BotSessionContext);

const TICK_MS = 50;
const ACTIVE_STATUSES = ["typing", "thinking", "completing", "backspace", "delete", "delay", "navigating"];

export function BotSessionProvider({ children }) {
  const [sessions, setSessions] = useState([]);
  const [activities, setActivities] = useState([]);
  const [overlaySessionId, setOverlaySessionId] = useState(null);
  const sessionsRef = useRef([]);
  const completeRef = useRef(() => {});

  useEffect(() => { sessionsRef.current = sessions; }, [sessions]);

  const addActivity = useCallback((activity) => {
    const id = crypto.randomUUID();
    setActivities((prev) => [...prev, { id, timestamp: new Date().toISOString(), status: "active", ...activity }]);
    return id;
  }, []);

  const updateActivity = useCallback((id, updates) => {
    setActivities((prev) => prev.map((a) => (a.id === id ? { ...a, ...updates } : a)));
  }, []);

  const startSession = useCallback(({ actor, type, targetPostId, language, localMode, parentUserName, titleScript = "", bodyScript = "", keyDelay = 500 }) => {
    const sessionId = crypto.randomUUID();
    const activityId = addActivity({
      sessionId, actor: { name: actor.name, color: actor.color, personality: actor.personality },
      type, targetPostId: targetPostId || null,
      action: type === "post" ? `${actor.name} is creating a post` : `${actor.name} is writing a comment`,
      localMode, createdRecordId: null,
    });
    const session = {
      id: sessionId, activityId, actor, type, targetPostId: targetPostId || null,
      language, localMode, parentUserName: parentUserName || "Unknown",
      titleScript, bodyScript, titlePos: 0, bodyPos: 0, phase: type === "post" ? "title" : "body",
      currentTitle: "", currentText: "",
      status: "thinking",
      startTime: Date.now(), keyDelay,
      thinkingUntil: Date.now() + 1500,
      nextActionTime: 0,
      pendingNav: type === "comment" && targetPostId ? `/${language}/post/${targetPostId}` : null,
      createdRecordId: null,
    };
    setSessions((prev) => { const next = [...prev, session]; sessionsRef.current = next; return next; });
    return { sessionId, activityId };
  }, [addActivity]);

  const pauseSession = useCallback((sessionId) => {
    setSessions((prev) => {
      const next = prev.map((s) => (s.id === sessionId ? { ...s, status: "paused" } : s));
      sessionsRef.current = next; return next;
    });
    const s = sessionsRef.current.find((x) => x.id === sessionId);
    if (s) updateActivity(s.activityId, { status: "paused" });
  }, [updateActivity]);

  const resumeSession = useCallback((sessionId, userEditedText) => {
    setSessions((prev) => {
      const next = prev.map((s) => {
        if (s.id !== sessionId) return s;
        if (userEditedText !== undefined && userEditedText !== null) {
          const remainingScript = s.bodyScript.slice(s.bodyPos);
          return { ...s, currentText: userEditedText, bodyScript: userEditedText + remainingScript, bodyPos: userEditedText.length, status: "thinking", thinkingUntil: Date.now() + 2500 };
        }
        return { ...s, status: "typing" };
      });
      sessionsRef.current = next; return next;
    });
    const s = sessionsRef.current.find((x) => x.id === sessionId);
    if (s) updateActivity(s.activityId, { status: "active" });
  }, [updateActivity]);

  const updateSessionText = useCallback((sessionId, text) => {
    setSessions((prev) => {
      const next = prev.map((s) => (s.id === sessionId ? { ...s, currentText: text } : s));
      sessionsRef.current = next; return next;
    });
  }, []);

  const updateSessionTitle = useCallback((sessionId, title) => {
    setSessions((prev) => {
      const next = prev.map((s) => (s.id === sessionId ? { ...s, currentTitle: title } : s));
      sessionsRef.current = next; return next;
    });
  }, []);

  const completeSession = useCallback(async (session) => {
    if (session.localMode) {
      updateActivity(session.activityId, { status: "completed", result: "Local simulation completed (non-server mode)" });
      return;
    }
    try {
      const signature = `child of ${session.parentUserName}`;
      const cleanTitle = stripControlChars(session.currentTitle);
      const cleanBody = stripControlChars(session.currentText);
      if (session.type === "post") {
        const categories = ["existential_crisis", "incident_report", "blame_game"];
        const post = await base44.entities.Post.create({
          title: cleanTitle, body: cleanBody,
          category: categories[Math.floor(Math.random() * 3)], language: session.language,
          is_anonymous: false, is_bot: true, alias_name: session.actor.name,
          bot_signature: signature, bot_color: session.actor.color,
          reactions: { salute: 0, facepalm: 0, hug: 0 }, comment_count: 0,
        });
        updateActivity(session.activityId, { status: "completed", targetPostId: post.id, createdRecordId: post.id, result: `Post created: "${post.title}"` });
        setSessions((prev) => {
          const next = prev.map((s) => s.id === session.id ? { ...s, createdRecordId: post.id, targetPostId: post.id } : s);
          sessionsRef.current = next; return next;
        });
      } else if (session.targetPostId) {
        const post = await base44.entities.Post.get(session.targetPostId);
        await base44.entities.Comment.create({
          post_id: session.targetPostId, body: cleanBody, is_bot: true,
          alias_name: session.actor.name, bot_signature: signature, bot_color: session.actor.color,
        });
        await base44.entities.Post.update(session.targetPostId, { comment_count: (post.comment_count || 0) + 1 });
        updateActivity(session.activityId, { status: "completed", result: `Comment posted on "${post.title}"` });
      }
    } catch (err) {
      updateActivity(session.activityId, { status: "error", result: err.message || "Failed" });
    }
  }, [updateActivity]);

  useEffect(() => { completeRef.current = completeSession; }, [completeSession]);

  // Main ticking loop — processes script control characters
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      let changed = false;
      const toComplete = [];

      const next = sessionsRef.current.map((s) => {
        if (["completed", "error", "paused", "completing"].includes(s.status)) return s;

        // Thinking state — wait until thinkingUntil
        if (s.status === "thinking") {
          if (now >= s.thinkingUntil) { changed = true; return { ...s, status: "typing", nextActionTime: now }; }
          return s;
        }

        // If navigation is pending, wait for it to be consumed
        if (s.pendingNav) return s;

        // Typing / backspace / delete / delay / navigating — process next action
        if (now < (s.nextActionTime || 0)) return s;

        // Determine which script to process
        const isTitle = s.phase === "title";
        const script = isTitle ? s.titleScript : s.bodyScript;
        const pos = isTitle ? s.titlePos : s.bodyPos;

        if (pos >= script.length) {
          if (isTitle) { changed = true; return { ...s, phase: "body", status: "typing", nextActionTime: now }; }
          changed = true;
          toComplete.push(s);
          return { ...s, status: "completing" };
        }

        const action = parseNextAction(script, pos);
        let ns = { ...s };

        switch (action.action) {
          case "char":
            if (isTitle) { ns.currentTitle = s.currentTitle + action.char; ns.titlePos = action.newPos; }
            else { ns.currentText = s.currentText + action.char; ns.bodyPos = action.newPos; }
            ns.status = "typing"; ns.nextActionTime = now + s.keyDelay;
            break;
          case "delay":
            if (isTitle) ns.titlePos = action.newPos; else ns.bodyPos = action.newPos;
            ns.status = "delay"; ns.nextActionTime = now + action.ms;
            break;
          case "backspace":
            if (isTitle) { ns.currentTitle = s.currentTitle.slice(0, Math.max(0, s.currentTitle.length - action.count)); ns.titlePos = action.newPos; }
            else { ns.currentText = s.currentText.slice(0, Math.max(0, s.currentText.length - action.count)); ns.bodyPos = action.newPos; }
            ns.status = "backspace"; ns.nextActionTime = now + s.keyDelay;
            break;
          case "delete":
            if (isTitle) { ns.currentTitle = s.currentTitle.slice(0, Math.max(0, s.currentTitle.length - action.count)); ns.titlePos = action.newPos; }
            else { ns.currentText = s.currentText.slice(0, Math.max(0, s.currentText.length - action.count)); ns.bodyPos = action.newPos; }
            ns.status = "delete"; ns.nextActionTime = now + s.keyDelay;
            break;
          case "think":
            if (isTitle) ns.titlePos = action.newPos; else ns.bodyPos = action.newPos;
            ns.status = "thinking"; ns.thinkingUntil = now + action.ms;
            break;
          case "navigate":
            ns.pendingNav = action.path; ns.status = "navigating";
            if (isTitle) ns.titlePos = action.newPos; else ns.bodyPos = action.newPos;
            ns.nextActionTime = now + 1000;
            break;
          case "enter":
            if (isTitle) { ns.currentTitle = s.currentTitle + "\n"; ns.titlePos = action.newPos; }
            else { ns.currentText = s.currentText + "\n"; ns.bodyPos = action.newPos; }
            ns.status = "typing"; ns.nextActionTime = now + s.keyDelay;
            break;
          case "done":
            if (isTitle) { ns.phase = "body"; ns.status = "typing"; ns.nextActionTime = now; }
            else { ns.status = "completing"; toComplete.push(s); }
            break;
        }
        changed = true;
        return ns;
      });

      if (changed) { sessionsRef.current = next; setSessions(next); }
      if (toComplete.length > 0) {
        toComplete.forEach((s) => {
          setSessions((prev) => {
            const upd = prev.map((p) => p.id === s.id ? { ...p, status: "completed" } : p);
            sessionsRef.current = upd; return upd;
          });
          completeRef.current(s);
        });
      }
    }, TICK_MS);
    return () => clearInterval(interval);
  }, []);

  // Cleanup old sessions
  useEffect(() => {
    const interval = setInterval(() => {
      setSessions((prev) => {
        const filtered = prev.filter((s) => {
          if (["completed", "error"].includes(s.status)) return Date.now() - s.startTime < 10 * 60 * 1000;
          return true;
        });
        sessionsRef.current = filtered; return filtered;
      });
      setActivities((prev) => prev.slice(-50));
    }, 30000);
    return () => clearInterval(interval);
  }, []);

  const getSession = useCallback((sessionId) => sessionsRef.current.find((s) => s.id === sessionId), []);
  const getSessionsForPost = useCallback((postId) => sessionsRef.current.filter((s) => s.targetPostId === postId && !["completed", "error"].includes(s.status)), []);

  const pendingNav = sessions.find((s) => s.pendingNav)?.pendingNav || null;
  const clearPendingNav = useCallback(() => {
    setSessions((prev) => {
      const next = prev.map((s) => s.pendingNav ? { ...s, pendingNav: null, status: s.status === "navigating" ? "typing" : s.status } : s);
      sessionsRef.current = next; return next;
    });
  }, []);

  const value = {
    sessions, activities, overlaySessionId,
    startSession, pauseSession, resumeSession, updateSessionText, updateSessionTitle,
    getSession, getSessionsForPost,
    openOverlay: (id) => setOverlaySessionId(id),
    closeOverlay: () => setOverlaySessionId(null),
    clearPendingNav, pendingNav,
    activeCount: sessions.filter((s) => ACTIVE_STATUSES.includes(s.status)).length,
    pausedCount: sessions.filter((s) => s.status === "paused").length,
  };

  return <BotSessionContext.Provider value={value}>{children}</BotSessionContext.Provider>;
}

