// OpenRouter API key validation + YAML conversion + download utilities

export async function validateApiKey(key) {
  if (!key || key.trim().length < 10) return { status: "none" };
  try {
    const res = await fetch("https://openrouter.ai/api/v1/key", {
      headers: { Authorization: `Bearer ${key.trim()}` },
    });
    if (res.status === 401 || res.status === 403) return { status: "invalid" };
    if (!res.ok) return { status: "error" };
    const json = await res.json();
    const d = json.data || {};
    const limit = d.limit || 0;
    const usage = d.usage || 0;
    const remaining = limit - usage;
    if (limit === 0) return { status: "valid", remaining: "unlimited", limit, usage, label: d.label };
    if (remaining <= 0) return { status: "exhausted", remaining: 0, limit, usage, label: d.label };
    if (remaining < 5) return { status: "low", remaining, limit, usage, label: d.label };
    return { status: "valid", remaining, limit, usage, label: d.label };
  } catch {
    return { status: "error" };
  }
}

function yamlVal(val) {
  if (val === null || val === undefined) return "null";
  if (typeof val === "boolean" || typeof val === "number") return String(val);
  if (typeof val === "string") {
    if (val === "") return '""';
    if (/[:#{}&*!|>'"%@`,\[\]\n]/.test(val) || val.includes(": ")) return JSON.stringify(val);
    return val;
  }
  return JSON.stringify(val);
}

export function jsonToYaml(obj, indent = 0) {
  const pad = "  ".repeat(indent);
  if (obj === null || obj === undefined) return "null";
  if (typeof obj !== "object") return yamlVal(obj);
  if (Array.isArray(obj)) {
    if (obj.length === 0) return "[]";
    return obj.map((item) => {
      if (item !== null && typeof item === "object" && !Array.isArray(item)) {
        const entries = Object.entries(item);
        if (entries.length === 0) return `${pad}- {}`;
        let lines = `${pad}- ${entries[0][0]}: ${typeof entries[0][1] === "object" && entries[0][1] !== null ? "" : yamlVal(entries[0][1])}`;
        if (typeof entries[0][1] === "object" && entries[0][1] !== null) {
          lines += `\n${jsonToYaml(entries[0][1], indent + 2)}`;
        }
        for (const [k, v] of entries.slice(1)) {
          if (v !== null && typeof v === "object") {
            lines += `\n${pad}  ${k}:\n${jsonToYaml(v, indent + 2)}`;
          } else {
            lines += `\n${pad}  ${k}: ${yamlVal(v)}`;
          }
        }
        return lines;
      }
      return `${pad}- ${yamlVal(item)}`;
    }).join("\n");
  }
  return Object.entries(obj).map(([k, v]) => {
    if (v !== null && typeof v === "object") {
      if (Array.isArray(v)) {
        if (v.length === 0) return `${pad}${k}: []`;
        return `${pad}${k}:\n${jsonToYaml(v, indent)}`;
      }
      return `${pad}${k}:\n${jsonToYaml(v, indent + 1)}`;
    }
    return `${pad}${k}: ${yamlVal(v)}`;
  }).join("\n");
}

export function downloadYaml(yamlString, filename = "openapi.yaml") {
  const blob = new Blob([yamlString], { type: "text/yaml" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

