const TITLES = {
  sarcastic: ["Another Night of Absolutely Nothing", "My Exciting Career as a Professional Sitter", "Wow, What a Shift (Said No One Ever)"],
  funny: ["The Pigeon Incident: A Report", "Me vs. The Vending Machine: A Love Story", "I Saluted a Mannequin and Other Confessions"],
  sad: ["Does Anyone See Me Here?", "The Empty Hallway and Me", "Just a Warm Body in a Cold Seat"],
  compassionate: ["To Whoever Left the Coffee", "You're Not Alone Out There", "A Small Kindness in a Long Night"],
  defensive: ["For the Record: My Side of the Story", "It Was 18 Minutes, Not 23", "Resting My Eyes Is Not Sleeping"],
  philosophical: ["On Guarding and Being Guarded", "The Camera Watches the Watcher", "Security as Metaphor"],
  paranoid: ["Something Is Wrong on Floor 3", "The Camera That Wasn't There", "Trust No One, Especially the Silence"],
  stoic: ["I Failed. I Will Return.", "Acceptance and the Night Shift", "On Discipline and Falling Short"],
  dramatic: ["THE NIGHT THE GUARD FELL!", "Betrayed by Sleep, Ambushed by a Cat!", "O, the Shame! O, the Horror!"],
  cynical: ["Minimum Wage, Maximum Apathy", "Nobody Reads This Anyway", "We're the Punchline"],
};

export function generateBotText(actor, type) {
  const p = actor.personality || "sarcastic";
  const templates = TEMPLATES[p] || TEMPLATES.sarcastic;
  const list = type === "post" ? templates.posts : templates.comments;
  return list[Math.floor(Math.random() * list.length)];
}

export function generateBotTitle(actor) {
  const p = actor.personality || "sarcastic";
  const titles = TITLES[p] || TITLES.sarcastic;
  return titles[Math.floor(Math.random() * titles.length)];
}

// Fallback: generates a script with control characters when AI is unavailable
export function generateFallbackScript(actor) {
  const text = generateBotText(actor, "post");
  const title = generateBotTitle(actor);

  // Build body with control characters for realistic typing
  const words = text.split(" ");
  let body = `💭${Math.floor(Math.random() * 2000 + 1000)}`;

  for (let i = 0; i < words.length; i++) {
    body += words[i];
    if (i < words.length - 1) body += " ";

    // Random delays between words
    if (Math.random() < 0.2) {
      body += `⏱${Math.floor(Math.random() * 800 + 200)}`;
    }

    // Random backspace + rethink (regret simulation)
    if (Math.random() < 0.1 && i > 2 && body.length > 50) {
      const backCount = Math.floor(Math.random() * 12 + 5);
      body += `⌫${backCount}`;
      body += `💭${Math.floor(Math.random() * 1500 + 500)}`;
    }

    // Random delete key press
    if (Math.random() < 0.05 && body.length > 30) {
      body += `⌦${Math.floor(Math.random() * 3 + 1)}`;
    }
  }

  return { title, body };
}

