import React, { useState, useEffect } from "react";
import { useOutletContext } from "react-router-dom";
import { t, SUPPORTED_LANGS, LANG_LABELS } from "@/lib/i18n";
import { base44 } from "@/api/base44Client";
import { getServerAddress } from "@/lib/serverConfig";
import { useBotSessions } from "@/lib/BotSessionContext";
import { generateAiScripts } from "@/lib/aiScriptGenerator";
import { Bot, Zap, Edit3, Trash2, Loader2, Wifi, WifiOff } from "lucide-react";
import { Slider } from "@/components/ui/slider";

const PERSONALITIES = ["sarcastic", "funny", "sad", "compassionate", "defensive", "philosophical", "paranoid", "stoic", "dramatic", "cynical"];
const BOT_COLORS = ["#EF4444", "#F97316", "#EAB308", "#22C55E", "#06B6D4", "#3B82F6", "#8B5CF6", "#EC4899", "#F43F5E", "#14B8A6"];

const DEFAULT_ACTORS = PERSONALITIES.map((p, i) => ({
  name: `Guard_${p.charAt(0).toUpperCase() + p.slice(1)}`,
  description: `A ${p} security guard who expresses their failures with a ${p} attitude`,
  personality: p,
  color: BOT_COLORS[i],
  is_active: true,
}));

export default function Simulation() {
  const { lang, theme, user } = useOutletContext();
  const { startSession, activeCount } = useBotSessions();
  const [actors, setActors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [generating, setGenerating] = useState(false);
  const [simLang, setSimLang] = useState(lang);
  const [keyDelay, setKeyDelay] = useState([0.5]);
  const [localMode, setLocalMode] = useState(!getServerAddress());
  const [editingActor, setEditingActor] = useState(null);
  const [editForm, setEditForm] = useState({ name: "", description: "" });

  useEffect(() => { loadActors(); }, []);

  const loadActors = async () => {
    setLoading(true);
    try {
      const existing = await base44.entities.AiActor.list("-created_date", 50);
      if (existing.length === 0) {
        const created = await base44.entities.AiActor.bulkCreate(DEFAULT_ACTORS);
        setActors(created);
      } else {
        setActors(existing);
      }
    } finally {
      setLoading(false);
    }
  };

  const startEdit = (actor) => {
    setEditingActor(actor.id);
    setEditForm({ name: actor.name, description: actor.description });
  };

  const saveEdit = async (id) => {
    await base44.entities.AiActor.update(id, editForm);
    setEditingActor(null);
    loadActors();
  };

  const deleteActor = async (id) => {
    if (!confirm(t(lang, "confirm_delete"))) return;
    await base44.entities.AiActor.delete(id);
    loadActors();
  };

  const handleGenerate = async () => {
    setGenerating(true);
    try {
      const scripts = await generateAiScripts({ actors, language: simLang, user, localMode });
      scripts.forEach(script => {
        startSession({
          actor: script.actor,
          type: script.action_type === "comment_on_post" ? "comment" : "post",
          targetPostId: script.target_post_id,
          language: script.language || simLang,
          localMode,
          parentUserName: user?.full_name || user?.email || "Unknown",
          titleScript: script.title || "",
          bodyScript: script.body || "",
          keyDelay: keyDelay[0] * 1000,
        });
      });
    } finally {
      setGenerating(false);
    }
  };

  if (loading) {
    return <div className="flex justify-center py-20"><Loader2 className={`w-6 h-6 animate-spin ${theme.textMuted}`} /></div>;
  }

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="font-heading text-2xl font-bold flex items-center gap-2">
          <Bot className="w-6 h-6" />
          {t(lang, "simulation")}
        </h1>
        <button
          onClick={handleGenerate}
          disabled={generating}
          className={`${theme.accent} ${theme.accentHover} px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 disabled:opacity-50`}
        >
          {generating ? <Loader2 className="w-4 h-4 animate-spin" /> : <Zap className="w-4 h-4" />}
          {generating ? t(lang, "generating") : t(lang, "generate_noise")}
        </button>
      </div>

      {/* Controls */}
      <div className={`${theme.card} rounded-xl p-5 border ${theme.border} grid sm:grid-cols-3 gap-4`}>
        <div>
          <label className="text-xs font-medium mb-2 block">{t(lang, "language")}</label>
          <select value={simLang} onChange={(e) => setSimLang(e.target.value)} className={`w-full rounded-lg px-3 py-2 text-sm ${theme.input}`}>
            {SUPPORTED_LANGS.map((l) => <option key={l} value={l}>{LANG_LABELS[l]}</option>)}
          </select>
        </div>
        <div>
          <label className="text-xs font-medium mb-2 block">{t(lang, "key_delay")}: {keyDelay[0].toFixed(1)}s</label>
          <Slider value={keyDelay} onValueChange={setKeyDelay} min={0} max={3} step={0.1} className="mt-3" />
        </div>
        <div className="flex items-end">
          <button
            onClick={() => setLocalMode(!localMode)}
            className={`flex items-center gap-2 text-sm px-3 py-2 rounded-lg transition-colors w-full justify-center ${localMode ? theme.badge : theme.accent}`}
          >
            {localMode ? <WifiOff className="w-4 h-4" /> : <Wifi className="w-4 h-4" />}
            {t(lang, "local_mode")}
          </button>
        </div>
      </div>

      {localMode && (
        <div className={`${theme.destructive} border rounded-xl p-3 text-xs`}>
          ⚠️ {t(lang, "local_mode")} — bot sessions will simulate typing but won't create actual posts/comments.
        </div>
      )}

      {/* Actors */}
      <div className={`${theme.card} rounded-xl p-5 border ${theme.border}`}>
        <h2 className="font-heading font-semibold mb-4">{t(lang, "actors")} ({actors.length})</h2>
        <div className="grid gap-2">
          {actors.map((actor) => (
            <div key={actor.id} className={`flex items-center gap-3 ${theme.secondaryBg} rounded-lg px-4 py-3`}>
              <div className="w-3 h-3 rounded-full shrink-0" style={{ backgroundColor: actor.color }} />
              {editingActor === actor.id ? (
                <div className="flex-1 flex items-center gap-2">
                  <input value={editForm.name} onChange={(e) => setEditForm({ ...editForm, name: e.target.value })} className={`rounded border px-2 py-1 text-sm flex-1 ${theme.input}`} />
                  <input value={editForm.description} onChange={(e) => setEditForm({ ...editForm, description: e.target.value })} className={`rounded border px-2 py-1 text-sm flex-1 ${theme.input}`} />
                  <button onClick={() => saveEdit(actor.id)} className={`text-xs px-3 py-1 rounded ${theme.accent}`}>{t(lang, "save")}</button>
                  <button onClick={() => setEditingActor(null)} className="text-xs px-3 py-1 rounded hover:bg-muted">{t(lang, "cancel")}</button>
                </div>
              ) : (
                <>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium truncate">{actor.name}</p>
                    <p className={`text-xs ${theme.textMuted} truncate`}>{actor.personality} · {actor.description}</p>
                  </div>
                  <div className="flex items-center gap-1 shrink-0">
                    <button onClick={() => startEdit(actor)} className={`p-1.5 rounded hover:bg-muted ${theme.textMuted}`}>
                      <Edit3 className="w-3.5 h-3.5" />
                    </button>
                    <button onClick={() => deleteActor(actor.id)} className="p-1.5 rounded hover:bg-muted text-red-500">
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>
                  </div>
                </>
              )}
            </div>
          ))}
        </div>
      </div>

      <div className={`${theme.secondaryBg} rounded-xl p-4 text-center`}>
        <p className={`text-sm ${theme.textMuted}`}>
          {activeCount > 0 ? `🤖 ${activeCount} bot session(s) active — check the Activity Log (bottom-right) to watch them work and navigate between pages.` : "Click Generate Noise — the AI will design bot activities with realistic typing, pauses, backspaces, and page navigation."}
        </p>
      </div>
    </div>
  );
}

