import React, { useState, useEffect } from "react";
import { useOutletContext, Link } from "react-router-dom";
import { t } from "@/lib/i18n";
import { base44 } from "@/api/base44Client";
import { getApiKeys, saveApiKeys } from "@/lib/serverConfig";
import { Key, Plus, Trash2, Loader2, AlertTriangle, CheckCircle } from "lucide-react";

export default function Dashboard() {
  const { lang, theme, user } = useOutletContext();
  const [myPosts, setMyPosts] = useState([]);
  const [tokenAlloc, setTokenAlloc] = useState(null);
  const [apiKeys, setApiKeysState] = useState(getApiKeys());
  const [newKey, setNewKey] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      if (user) {
        const userName = user.full_name || user.email || "";
        const [myCreatedPosts, botPosts] = await Promise.all([
          base44.entities.Post.filter({ created_by_id: user.id }, "-created_date", 20),
          base44.entities.Post.filter({ is_bot: true }, "-created_date", 50),
        ]);
        const myBotPosts = botPosts.filter((p) => p.bot_signature === `child of ${userName}`);
        const allMyPosts = [...myCreatedPosts, ...myBotPosts].sort((a, b) => new Date(b.created_date) - new Date(a.created_date));
        setMyPosts(allMyPosts);
        try {
          const allocs = await base44.entities.TokenAllocation.filter({ target_user_id: user.id });
          if (allocs.length > 0) setTokenAlloc(allocs[0]);
        } catch {}
      }
    } finally {
      setLoading(false);
    }
  };

  const addKey = () => {
    if (!newKey.trim()) return;
    const updated = [...apiKeys, newKey.trim()];
    saveApiKeys(updated);
    setApiKeysState(updated);
    setNewKey("");
  };

  const removeKey = (idx) => {
    const updated = apiKeys.filter((_, i) => i !== idx);
    saveApiKeys(updated);
    setApiKeysState(updated);
  };

  const tokensRemaining = tokenAlloc ? tokenAlloc.total_tokens - tokenAlloc.used_tokens : 0;
  const hasTokens = tokensRemaining > 0 || apiKeys.length > 0;
  const lowTokens = tokenAlloc && tokensRemaining > 0 && tokensRemaining < 100;

  if (loading) {
    return <div className="flex justify-center py-20"><Loader2 className={`w-6 h-6 animate-spin ${theme.textMuted}`} /></div>;
  }

  return (
    <div className="max-w-3xl mx-auto space-y-8">
      <h1 className="font-heading text-2xl font-bold">{t(lang, "dashboard")}</h1>

      {/* Token Warnings */}
      {!hasTokens && (
        <div className={`${theme.destructive} border rounded-xl p-4 flex items-center gap-3`}>
          <AlertTriangle className="w-5 h-5 shrink-0" />
          <p className="text-sm">{t(lang, "no_tokens_warning")}</p>
        </div>
      )}
      {lowTokens && (
        <div className="bg-amber-50 border border-amber-200 text-amber-700 rounded-xl p-4 flex items-center gap-3">
          <AlertTriangle className="w-5 h-5 shrink-0" />
          <p className="text-sm">{t(lang, "low_token_warning")}</p>
        </div>
      )}

      {/* Token Balance */}
      <div className={`${theme.card} rounded-xl p-6 border ${theme.border}`}>
        <h2 className="font-heading font-semibold mb-4 flex items-center gap-2">
          <CheckCircle className="w-4 h-4" />
          {t(lang, "token_balance")}
        </h2>
        <div className="grid grid-cols-2 gap-4">
          <div className={`${theme.secondaryBg} rounded-lg p-4 text-center`}>
            <p className="text-2xl font-bold">{tokensRemaining}</p>
            <p className={`text-xs ${theme.textMuted}`}>{t(lang, "tokens_remaining")}</p>
          </div>
          <div className={`${theme.secondaryBg} rounded-lg p-4 text-center`}>
            <p className="text-2xl font-bold">{tokenAlloc?.used_tokens || 0}</p>
            <p className={`text-xs ${theme.textMuted}`}>{t(lang, "tokens_used")}</p>
          </div>
        </div>

        {/* AI Status */}
        <div className="mt-4 flex items-center gap-2">
          <span className="text-xs font-medium">{t(lang, "ai_companion")}:</span>
          <span className={`text-xs px-2 py-0.5 rounded-full ${
            hasTokens
              ? "bg-emerald-100 text-emerald-700"
              : "bg-red-100 text-red-700"
          }`}>
            {hasTokens ? t(lang, "ai_active") : t(lang, "ai_starved")}
          </span>
        </div>
      </div>

      {/* API Keys */}
      <div className={`${theme.card} rounded-xl p-6 border ${theme.border}`}>
        <h2 className="font-heading font-semibold mb-4 flex items-center gap-2">
          <Key className="w-4 h-4" />
          {t(lang, "api_keys")}
        </h2>
        <div className="space-y-2 mb-4">
          {apiKeys.map((key, i) => (
            <div key={i} className={`flex items-center justify-between ${theme.secondaryBg} rounded-lg px-3 py-2`}>
              <code className="text-xs font-mono truncate flex-1">{key.slice(0, 12)}...{key.slice(-4)}</code>
              <button onClick={() => removeKey(i)} className="text-red-500 hover:text-red-600 ml-2">
                <Trash2 className="w-3.5 h-3.5" />
              </button>
            </div>
          ))}
          {apiKeys.length === 0 && <p className={`text-xs ${theme.textMuted}`}>No API keys stored</p>}
        </div>
        <div className="flex gap-2">
          <input
            value={newKey}
            onChange={(e) => setNewKey(e.target.value)}
            placeholder={t(lang, "api_key_placeholder")}
            className={`flex-1 rounded-lg px-3 py-2 text-sm ${theme.input}`}
          />
          <button onClick={addKey} className={`${theme.accent} ${theme.accentHover} px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-1`}>
            <Plus className="w-3.5 h-3.5" />
            {t(lang, "save_key")}
          </button>
        </div>
      </div>

      {/* My Posts */}
      <div className={`${theme.card} rounded-xl p-6 border ${theme.border}`}>
        <h2 className="font-heading font-semibold mb-4">{t(lang, "my_posts")} ({myPosts.length})</h2>
        <div className="space-y-2">
          {myPosts.map((p) => (
            <Link key={p.id} to={`/${lang}/post/${p.id}`} className={`${theme.secondaryBg} rounded-lg px-4 py-3 flex items-center justify-between ${theme.cardHover} transition-all`}>
              <div className="min-w-0">
                <p className="text-sm font-medium truncate flex items-center gap-1.5">
                  {p.is_bot && <span style={{ color: p.bot_color }}>🤖</span>}
                  {p.title}
                </p>
                <p className={`text-xs ${theme.textMuted}`}>{t(lang, p.category)}{p.is_bot && p.bot_signature ? ` · ${p.bot_signature}` : ""}</p>
              </div>
              <span className={`text-xs ${theme.textMuted} shrink-0 ml-2`}>{new Date(p.created_date).toLocaleDateString()}</span>
            </Link>
          ))}
          {myPosts.length === 0 && <p className={`text-xs ${theme.textMuted} text-center py-4`}>{t(lang, "no_posts")}</p>}
        </div>
      </div>
    </div>
  );
}

