import React, { useState, useEffect } from "react";
import { useOutletContext } from "react-router-dom";
import { t } from "@/lib/i18n";
import { base44 } from "@/api/base44Client";
import PostCard from "@/components/posts/PostCard";
import CreatePostModal from "@/components/posts/CreatePostModal";
import { Loader2 } from "lucide-react";

export default function Feed() {
  const { lang, theme, filterLang } = useOutletContext();
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState("all");

  const loadPosts = async () => {
    setLoading(true);
    try {
      const query = {};
      if (filterLang && filterLang !== "all") query.language = filterLang;
      if (activeCategory !== "all") query.category = activeCategory;
      const data = Object.keys(query).length
        ? await base44.entities.Post.filter(query, "-created_date", 50)
        : await base44.entities.Post.list("-created_date", 50);
      setPosts(data);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadPosts();
  }, [filterLang, activeCategory]);

  const categories = [
    { key: "all", label: t(lang, "all_languages") },
    { key: "existential_crisis", label: "🌀 " + t(lang, "existential_crisis") },
    { key: "incident_report", label: "📋 " + t(lang, "incident_report") },
    { key: "blame_game", label: "👉 " + t(lang, "blame_game") },
  ];

  return (
    <div className="space-y-6">
      {/* Hero */}
      <div className="text-center py-8">
        <h1 className="font-heading text-3xl md:text-4xl font-bold tracking-tight mb-2">
          {t(lang, "app_name")}
        </h1>
        <p className={`text-sm ${theme.textMuted} max-w-md mx-auto`}>
          {t(lang, "tagline")}
        </p>
      </div>

      {/* Controls */}
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div className="flex items-center gap-2 overflow-x-auto pb-1 w-full sm:w-auto">
          {categories.map((c) => (
            <button
              key={c.key}
              onClick={() => setActiveCategory(c.key)}
              className={`whitespace-nowrap text-xs px-3 py-1.5 rounded-full font-medium transition-colors ${
                activeCategory === c.key ? theme.accent : theme.badge + " " + theme.cardHover
              }`}
            >
              {c.label}
            </button>
          ))}
        </div>
        <CreatePostModal onCreated={loadPosts} />
      </div>

      {/* Posts Grid */}
      {loading ? (
        <div className="flex justify-center py-20">
          <Loader2 className={`w-6 h-6 animate-spin ${theme.textMuted}`} />
        </div>
      ) : posts.length === 0 ? (
        <div className={`text-center py-20 ${theme.textMuted}`}>
          <p className="text-lg mb-1">🛡️</p>
          <p className="text-sm">{t(lang, "no_posts")}</p>
        </div>
      ) : (
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {posts.map((post) => (
            <PostCard key={post.id} post={post} />
          ))}
        </div>
      )}
    </div>
  );
}

