import React, { useState, useMemo } from "react";
import { useOutletContext } from "react-router-dom";
import { t } from "@/lib/i18n";
import { openapiSpec } from "@/lib/openapi-spec";
import { getServerAddress, setServerAddress } from "@/lib/serverConfig";
import { FileText, Server, ChevronDown, ChevronRight, Copy, Check, ExternalLink, Download } from "lucide-react";
import { downloadYaml, jsonToYaml } from "@/lib/openrouter";

const METHOD_COLORS = {
  get: "bg-emerald-100 text-emerald-700",
  post: "bg-blue-100 text-blue-700",
  put: "bg-amber-100 text-amber-700",
  delete: "bg-red-100 text-red-700",
};

function EndpointCard({ path, method, spec, theme }) {
  const [expanded, setExpanded] = useState(false);
  const color = METHOD_COLORS[method] || "bg-gray-100 text-gray-700";

  return (
    <div className={`${theme.card} rounded-lg border ${theme.border} overflow-hidden`}>
      <button
        onClick={() => setExpanded(!expanded)}
        className={`w-full flex items-center gap-3 px-4 py-3 text-left hover:opacity-90 transition-opacity`}
      >
        <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded ${color}`}>{method}</span>
        <code className="text-xs font-mono flex-1 truncate">{path}</code>
        <span className={`text-xs ${theme.textMuted} hidden sm:block max-w-xs truncate`}>{spec.summary}</span>
        {expanded ? <ChevronDown className="w-3.5 h-3.5 shrink-0" /> : <ChevronRight className="w-3.5 h-3.5 shrink-0" />}
      </button>

      {expanded && (
        <div className={`px-4 pb-4 pt-2 border-t ${theme.border} space-y-3`}>
          <p className={`text-sm ${theme.textMuted}`}>{spec.summary}</p>

          {spec.tags && (
            <div className="flex gap-1">
              {spec.tags.map((tag) => (
                <span key={tag} className={`text-[10px] px-2 py-0.5 rounded-full ${theme.badge}`}>{tag}</span>
              ))}
            </div>
          )}

          {spec.security && (
            <p className="text-xs text-amber-600 flex items-center gap-1">🔐 Requires authentication</p>
          )}

          {spec.parameters && spec.parameters.length > 0 && (
            <div>
              <h4 className="text-xs font-semibold mb-2">Parameters</h4>
              <div className="space-y-1">
                {spec.parameters.map((p, i) => (
                  <div key={i} className={`flex items-center gap-2 text-xs ${theme.secondaryBg} rounded px-3 py-1.5`}>
                    <code className="font-mono font-medium">{p.name}</code>
                    <span className={theme.textMuted}>({p.in})</span>
                    {p.required && <span className="text-red-500 text-[10px]">required</span>}
                    {p.schema?.type && <span className={`${theme.textMuted} ml-auto`}>{p.schema.type}</span>}
                  </div>
                ))}
              </div>
            </div>
          )}

          {spec.requestBody && (
            <div>
              <h4 className="text-xs font-semibold mb-2">Request Body</h4>
              <pre className={`text-[10px] font-mono ${theme.secondaryBg} rounded-lg p-3 overflow-x-auto`}>
                {JSON.stringify(spec.requestBody.content?.["application/json"]?.schema, null, 2)}
              </pre>
            </div>
          )}

          {spec.responses && (
            <div>
              <h4 className="text-xs font-semibold mb-2">Responses</h4>
              <div className="space-y-1">
                {Object.entries(spec.responses).map(([code, resp]) => (
                  <div key={code} className={`flex items-center gap-2 text-xs ${theme.secondaryBg} rounded px-3 py-1.5`}>
                    <span className={`font-mono font-bold ${code.startsWith("2") ? "text-emerald-600" : "text-red-500"}`}>{code}</span>
                    <span className={theme.textMuted}>{resp.description}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export default function OpenApiDoc() {
  const { lang, theme } = useOutletContext();
  const [serverAddr, setServerAddr] = useState(getServerAddress());
  const [copied, setCopied] = useState(false);
  const [activeTag, setActiveTag] = useState("all");

  const handleServerChange = (val) => {
    setServerAddr(val);
    setServerAddress(val);
  };

  const tags = useMemo(() => {
    const allTags = new Set();
    Object.values(openapiSpec.paths).forEach((methods) => {
      Object.values(methods).forEach((spec) => {
        spec.tags?.forEach((tag) => allTags.add(tag));
      });
    });
    return ["all", ...Array.from(allTags)];
  }, []);

  const endpoints = useMemo(() => {
    const result = [];
    Object.entries(openapiSpec.paths).forEach(([path, methods]) => {
      Object.entries(methods).forEach(([method, spec]) => {
        if (activeTag === "all" || spec.tags?.includes(activeTag)) {
          result.push({ path, method, spec });
        }
      });
    });
    return result;
  }, [activeTag]);

  const getSpecWithServer = () => {
    const specWithServer = { ...openapiSpec };
    if (serverAddr) {
      specWithServer.servers = [{ url: serverAddr, description: "User-configured server" }];
    }
    return specWithServer;
  };

  const copySpec = () => {
    navigator.clipboard.writeText(JSON.stringify(getSpecWithServer(), null, 2));
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const downloadSpecYaml = () => {
    downloadYaml(jsonToYaml(getSpecWithServer()), "openapi.yaml");
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="font-heading text-2xl font-bold flex items-center gap-2">
          <FileText className="w-6 h-6" />
          {t(lang, "openapi_doc")}
        </h1>
        <div className="flex items-center gap-2">
          <button
            onClick={copySpec}
            className={`flex items-center gap-2 text-sm px-3 py-1.5 rounded-lg ${theme.badge} hover:opacity-80 transition-opacity`}
          >
            {copied ? <Check className="w-3.5 h-3.5 text-emerald-500" /> : <Copy className="w-3.5 h-3.5" />}
            {copied ? "Copied!" : "Copy JSON"}
          </button>
          <button
            onClick={downloadSpecYaml}
            className={`flex items-center gap-2 text-sm px-3 py-1.5 rounded-lg ${theme.badge} hover:opacity-80 transition-opacity`}
          >
            <Download className="w-3.5 h-3.5" />
            Download YAML
          </button>
        </div>
      </div>

      {/* Server Config */}
      <div className={`${theme.card} rounded-xl p-5 border ${theme.border}`}>
        <h2 className="text-sm font-semibold mb-3 flex items-center gap-2">
          <Server className="w-4 h-4" />
          {t(lang, "server_address")}
        </h2>
        <div className="flex gap-2">
          <input
            value={serverAddr}
            onChange={(e) => handleServerChange(e.target.value)}
            placeholder={t(lang, "server_address_placeholder")}
            className={`flex-1 rounded-lg px-3 py-2 text-sm font-mono ${theme.input}`}
          />
          <div className={`flex items-center gap-1.5 px-3 rounded-lg text-xs font-medium ${serverAddr ? "bg-emerald-100 text-emerald-700" : "bg-red-100 text-red-700"}`}>
            <div className={`w-1.5 h-1.5 rounded-full ${serverAddr ? "bg-emerald-500" : "bg-red-500"}`} />
            {serverAddr ? t(lang, "connected") : t(lang, "disconnected")}
          </div>
        </div>
        {serverAddr && (
          <p className={`text-xs ${theme.textMuted} mt-2 flex items-center gap-1`}>
            <ExternalLink className="w-3 h-3" />
            URL synced: {window.location.origin}{window.location.pathname}?server={encodeURIComponent(serverAddr)}
          </p>
        )}
      </div>

      {/* API Info */}
      <div className={`${theme.secondaryBg} rounded-xl p-5`}>
        <div className="grid grid-cols-3 gap-4 text-center">
          <div>
            <p className="text-lg font-bold">{openapiSpec.info.version}</p>
            <p className={`text-xs ${theme.textMuted}`}>Version</p>
          </div>
          <div>
            <p className="text-lg font-bold">{Object.keys(openapiSpec.paths).length}</p>
            <p className={`text-xs ${theme.textMuted}`}>Endpoints</p>
          </div>
          <div>
            <p className="text-lg font-bold">{tags.length - 1}</p>
            <p className={`text-xs ${theme.textMuted}`}>Tags</p>
          </div>
        </div>
      </div>

      {/* Tag Filter */}
      <div className="flex items-center gap-2 overflow-x-auto pb-1">
        {tags.map((tag) => (
          <button
            key={tag}
            onClick={() => setActiveTag(tag)}
            className={`whitespace-nowrap text-xs px-3 py-1.5 rounded-full font-medium transition-colors ${
              activeTag === tag ? theme.accent : theme.badge
            }`}
          >
            {tag === "all" ? "All" : tag}
          </button>
        ))}
      </div>

      {/* Endpoints */}
      <div className="space-y-2">
        {endpoints.map((ep, i) => (
          <EndpointCard key={i} path={ep.path} method={ep.method} spec={ep.spec} theme={theme} />
        ))}
      </div>
    </div>
  );
}

