  useEffect(() => {
    if (isAdmin) {
      loadAdminData();
    }
  }, [isAdmin]);

  const loadAdminData = async () => {
    try {
      const allocs = await base44.entities.TokenAllocation.list("-created_date", 100);
      const total = allocs.reduce((s, a) => s + (a.total_tokens || 0), 0);
      const used = allocs.reduce((s, a) => s + (a.used_tokens || 0), 0);
      setTokenOverview({ total, used, count: allocs.length });
      const global = allocs.find((a) => a.is_global_pool);
      if (global) setGlobalLimit(String(global.total_tokens));
    } catch {}
  };

  const handleServerSave = () => {
    setServerAddress(serverAddr);
  };

  const handleSetGlobalLimit = async () => {
    setSaving(true);
    try {
      const existing = await base44.entities.TokenAllocation.filter({ is_global_pool: true });
      if (existing.length > 0) {
        await base44.entities.TokenAllocation.update(existing[0].id, { total_tokens: Number(globalLimit) });
      } else {
        await base44.entities.TokenAllocation.create({ total_tokens: Number(globalLimit), is_global_pool: true });
      }
      loadAdminData();
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8">
      <h1 className="font-heading text-2xl font-bold flex items-center gap-2">
        <Settings className="w-6 h-6" />
        {t(lang, "settings")}
      </h1>

      {/* Server Address */}
      <section className={`${theme.card} rounded-xl p-6 border ${theme.border}`}>
        <h2 className="font-heading font-semibold mb-4 flex items-center gap-2">
          <Server className="w-4 h-4" />
          {t(lang, "server_address")}
        </h2>
        <div className="flex gap-2">
          <input
            value={serverAddr}
            onChange={(e) => setServerAddr(e.target.value)}
            placeholder={t(lang, "server_address_placeholder")}
            className={`flex-1 rounded-lg px-3 py-2 text-sm font-mono ${theme.input}`}
          />
          <button onClick={handleServerSave} className={`${theme.accent} ${theme.accentHover} px-4 py-2 rounded-lg text-sm font-medium`}>
            {t(lang, "save")}
          </button>
        </div>
        <p className={`text-xs ${theme.textMuted} mt-2`}>
          {t(lang, "api_status")}: {serverAddr ? "🟢 " + t(lang, "connected") : "🔴 " + t(lang, "disconnected")}
        </p>
      </section>

      {/* Theme */}
      <section className={`${theme.card} rounded-xl p-6 border ${theme.border}`}>
        <h2 className="font-heading font-semibold mb-4 flex items-center gap-2">
          <Palette className="w-4 h-4" />
          {t(lang, "theme")}
        </h2>
        <div className="grid grid-cols-3 gap-3">
          {Object.entries(THEMES).map(([key, th]) => (
            <button
              key={key}
              onClick={() => { setThemeNameLocal(key); setThemePref(key); window.location.reload(); }}
              className={`p-4 rounded-xl border-2 transition-all ${
                themeName === key ? "border-primary ring-2 ring-primary/20" : theme.border
              }`}
            >
              <div className={`w-full h-8 rounded-lg mb-2 ${th.bg}`}>
                <div className={`w-1/2 h-full rounded-lg ${th.accent}`} />
              </div>
              <p className="text-xs font-medium">{t(lang, key)}</p>
            </button>
          ))}
        </div>
      </section>

      {/* Admin Section */}
      {isAdmin && (
        <section className={`${theme.card} rounded-xl p-6 border ${theme.border}`}>
          <h2 className="font-heading font-semibold mb-4 flex items-center gap-2">
            <Shield className="w-4 h-4" />
            {t(lang, "admin")} — {t(lang, "global_token_limit")}
          </h2>

          {tokenOverview && (
            <div className="grid grid-cols-3 gap-4 mb-4">
              <div className={`${theme.secondaryBg} rounded-lg p-3 text-center`}>
                <p className="text-xl font-bold">{tokenOverview.total}</p>
                <p className={`text-xs ${theme.textMuted}`}>{t(lang, "total_tokens_distributed")}</p>
              </div>
              <div className={`${theme.secondaryBg} rounded-lg p-3 text-center`}>
                <p className="text-xl font-bold">{tokenOverview.used}</p>
                <p className={`text-xs ${theme.textMuted}`}>{t(lang, "tokens_used")}</p>
              </div>
              <div className={`${theme.secondaryBg} rounded-lg p-3 text-center`}>
                <p className="text-xl font-bold">{tokenOverview.count}</p>
                <p className={`text-xs ${theme.textMuted}`}>Allocations</p>
              </div>
            </div>
          )}

          <div className="flex gap-2">
            <input
              value={globalLimit}
              onChange={(e) => setGlobalLimit(e.target.value)}
              type="number"
              placeholder="10000"
              className={`flex-1 rounded-lg px-3 py-2 text-sm ${theme.input}`}
            />
            <button
              onClick={handleSetGlobalLimit}
              disabled={saving}
              className={`${theme.accent} ${theme.accentHover} px-4 py-2 rounded-lg text-sm font-medium disabled:opacity-50`}
            >
              {saving ? "..." : t(lang, "set_limit")}
            </button>
          </div>
        </section>
      )}
    </div>
  );
}

