import React, { useState, useEffect } from "react";
import { useParams, useOutletContext, useNavigate } from "react-router-dom";
import { t } from "@/lib/i18n";
import { base44 } from "@/api/base44Client";
import { useBotSessions } from "@/lib/BotSessionContext";
import BotTypingView from "@/components/bot/BotTypingView";
import { Switch } from "@/components/ui/switch";
import { ArrowLeft, User, Bot, Trash2, Edit3, Loader2, MessageSquare } from "lucide-react";
import moment from "moment";

export default function PostDetail() {
  const { id } = useParams();
  const { lang, theme, user } = useOutletContext();
  const { sessions, pauseSession, resumeSession, updateSessionText } = useBotSessions();
  const botSessions = sessions.filter((s) => s.targetPostId === id && !["completed", "error"].includes(s.status));
  const navigate = useNavigate();
  const [post, setPost] = useState(null);
  const [comments, setComments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [commentText, setCommentText] = useState("");
  const [isAnon, setIsAnon] = useState(false);
  const [aliasName, setAliasName] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [editing, setEditing] = useState(null);
  const [editText, setEditText] = useState("");

  useEffect(() => {
    loadData();
  }, [id]);

  const loadData = async () => {
    setLoading(true);
    try {
      const [p, c] = await Promise.all([
        base44.entities.Post.get(id),
        base44.entities.Comment.filter({ post_id: id }, "-created_date", 100),
      ]);
      setPost(p);
      setComments(c);
    } finally {
      setLoading(false);
    }
  };

  const addComment = async (e) => {
    e.preventDefault();
    if (!commentText.trim()) return;
    setSubmitting(true);
    try {
      const data = { post_id: id, body: commentText, is_anonymous: isAnon };
      if (isAnon && aliasName) data.alias_name = aliasName;
      await base44.entities.Comment.create(data);
      await base44.entities.Post.update(id, { comment_count: (post.comment_count || 0) + 1 });
      setCommentText("");
      setAliasName("");
      loadData();
    } finally {
      setSubmitting(false);
    }
  };

  const react = async (type) => {
    const reactions = { ...(post.reactions || { salute: 0, facepalm: 0, hug: 0 }) };
    reactions[type] = (reactions[type] || 0) + 1;
    await base44.entities.Post.update(id, { reactions });
    setPost({ ...post, reactions });
  };

  const deletePost = async () => {
    if (!confirm(t(lang, "confirm_delete"))) return;
    await base44.entities.Post.delete(id);
    navigate(`/${lang}/feed`);
  };

  const deleteComment = async (cId) => {
    if (!confirm(t(lang, "confirm_delete"))) return;
    await base44.entities.Comment.delete(cId);
    await base44.entities.Post.update(id, { comment_count: Math.max(0, (post.comment_count || 1) - 1) });
    loadData();
  };

  const saveEditComment = async (cId) => {
    await base44.entities.Comment.update(cId, { body: editText });
    setEditing(null);
    loadData();
  };

  if (loading) {
    return (
      <div className="flex justify-center py-20">
        <Loader2 className={`w-6 h-6 animate-spin ${theme.textMuted}`} />
      </div>
    );
  }

  if (!post) {
    return <div className={`text-center py-20 ${theme.textMuted}`}>Post not found</div>;
  }

  const isOwner = user && post.created_by_id === user.id;

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      <button onClick={() => navigate(`/${lang}/feed`)} className={`flex items-center gap-1 text-sm ${theme.textMuted} hover:opacity-80`}>
        <ArrowLeft className="w-4 h-4" /> {t(lang, "back")}
      </button>

      {/* Post */}
      <article className={`${theme.card} rounded-xl p-6 border ${theme.border}`} style={post.is_bot && post.bot_color ? { borderLeftWidth: "4px", borderLeftColor: post.bot_color } : {}}>
        <div className="flex items-start justify-between mb-4">
          <span className={`text-xs font-medium px-2 py-0.5 rounded-full ${theme.badge}`}>
            {t(lang, post.category)}
          </span>
          {isOwner && (
            <button onClick={deletePost} className="text-red-500 hover:text-red-600">
              <Trash2 className="w-4 h-4" />
            </button>
          )}
        </div>

        <h1 className="font-heading text-2xl font-bold mb-3">{post.title}</h1>
        <p className={`text-sm leading-relaxed mb-4 whitespace-pre-wrap`}>{post.body}</p>

        <div className={`flex items-center justify-between text-xs ${theme.textMuted} border-t border-current/5 pt-4`}>
          <div className="flex items-center gap-1.5">
            {post.is_bot ? <Bot className="w-3 h-3" /> : <User className="w-3 h-3" />}
            <span>
              {post.is_anonymous ? `${t(lang, "posted_anonymously")} ${post.alias_name}` : post.is_bot ? `🤖 ${post.alias_name}` : t(lang, "posted_by")}
            </span>
            {post.bot_signature && <span className="italic">({post.bot_signature})</span>}
          </div>
          <span>{moment(post.created_date).format("MMM D, YYYY · HH:mm")}</span>
        </div>

        {post.alias_description && (
          <div className={`mt-3 p-3 rounded-lg ${theme.secondaryBg} text-xs ${theme.textMuted} italic`}>
            "{post.alias_description}"
          </div>
        )}

        {/* Reactions */}
        <div className="flex items-center gap-2 mt-4 pt-4 border-t border-current/5">
          {[
            { key: "salute", emoji: "🫡" },
            { key: "facepalm", emoji: "🤦" },
            { key: "hug", emoji: "🫂" },
          ].map((r) => (
            <button
              key={r.key}
              onClick={() => react(r.key)}
              className={`flex items-center gap-1 text-xs px-3 py-1.5 rounded-full ${theme.badge} hover:opacity-80 transition-colors`}
            >
              {r.emoji} {post.reactions?.[r.key] || 0}
            </button>
          ))}
        </div>
      </article>

      {/* Comments */}
      <section className="space-y-4">
        <h2 className="font-heading font-semibold flex items-center gap-2">
          <MessageSquare className="w-4 h-4" />
          {t(lang, "comments")} ({comments.length})
        </h2>

        {comments.map((c) => {
          const cOwner = user && c.created_by_id === user.id;
          return (
            <div
              key={c.id}
              className={`${theme.card} rounded-lg p-4 border ${theme.border}`}
              style={c.is_bot && c.bot_color ? { borderLeftWidth: "3px", borderLeftColor: c.bot_color } : {}}
            >
              {editing === c.id ? (
                <div className="space-y-2">
                  <textarea value={editText} onChange={(e) => setEditText(e.target.value)} rows={2} className="w-full rounded border px-3 py-2 text-sm resize-none" />
                  <div className="flex gap-2">
                    <button onClick={() => saveEditComment(c.id)} className={`text-xs px-3 py-1 rounded ${theme.accent}`}>{t(lang, "save")}</button>
                    <button onClick={() => setEditing(null)} className="text-xs px-3 py-1 rounded hover:bg-muted">{t(lang, "cancel")}</button>
                  </div>
                </div>
              ) : (
                <>
                  <p className="text-sm whitespace-pre-wrap mb-2">{c.body}</p>
                  <div className={`flex items-center justify-between text-xs ${theme.textMuted}`}>
                    <div className="flex items-center gap-1.5">
                      {c.is_bot ? <Bot className="w-3 h-3" /> : <User className="w-3 h-3" />}
                      <span>{c.is_anonymous ? c.alias_name || t(lang, "anonymous") : c.is_bot ? `🤖 ${c.alias_name}` : ""}</span>
                      {c.bot_signature && <span className="italic">({c.bot_signature})</span>}
                    </div>
                    <div className="flex items-center gap-2">
                      <span>{moment(c.created_date).fromNow()}</span>
                      {cOwner && (
                        <>
                          <button onClick={() => { setEditing(c.id); setEditText(c.body); }}>
                            <Edit3 className="w-3 h-3 hover:text-blue-500" />
                          </button>
                          <button onClick={() => deleteComment(c.id)}>
                            <Trash2 className="w-3 h-3 hover:text-red-500" />
                          </button>
                        </>
                      )}
                    </div>
                  </div>
                </>
              )}
            </div>
          );
        })}

        {comments.length === 0 && (
          <p className={`text-center text-sm py-8 ${theme.textMuted}`}>{t(lang, "no_comments")}</p>
        )}

        {/* Active Bot Sessions */}
        {botSessions.map((session) => (
          <BotTypingView
            key={session.id}
            session={session}
            theme={theme}
            onPause={() => pauseSession(session.id)}
            onResume={(editedText) => resumeSession(session.id, editedText)}
            onTextChange={(text) => updateSessionText(session.id, text)}
            editable
          />
        ))}

        {/* New Comment */}
        <form onSubmit={addComment} className={`${theme.card} rounded-xl p-4 border ${theme.border} space-y-3`}>
          <textarea
            value={commentText}
            onChange={(e) => setCommentText(e.target.value)}
            rows={3}
            className={`w-full rounded-lg px-3 py-2 text-sm resize-none ${theme.input}`}
            placeholder={t(lang, "write_comment")}
          />
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2">
                <span className="text-xs">{t(lang, "anonymous")}</span>
                <Switch checked={isAnon} onCheckedChange={setIsAnon} />
              </div>
              {isAnon && (
                <input
                  value={aliasName}
                  onChange={(e) => setAliasName(e.target.value)}
                  placeholder={t(lang, "alias_name_placeholder")}
                  className={`rounded border px-2 py-1 text-xs ${theme.input}`}
                />
              )}
            </div>
            <button
              type="submit"
              disabled={submitting || !commentText.trim()}
              className={`${theme.accent} ${theme.accentHover} px-4 py-1.5 rounded-lg text-xs font-medium transition-colors disabled:opacity-50`}
            >
              {submitting ? "..." : t(lang, "submit")}
            </button>
          </div>
        </form>
      </section>
    </div>
  );
}

